+    py: Python<'_>,
+    fname: Py<PyAny>,
+    dtype: Option<Py<PyAny>>,
+    comments: &str,
+    delimiter: Option<&str>,
+    skip_header: i64,
+    skip_footer: i64,
+    converters: Option<Py<PyAny>>,
+    missing_values: Option<Py<PyAny>>,
+    filling_values: Option<Py<PyAny>>,
+    usecols: Option<Py<PyAny>>,
+    names: Option<Py<PyAny>>,
+    excludelist: Option<Py<PyAny>>,
